def fibonacci(n: int) -> int {
    if n <= 0 {
        return 0;
    }
    if n == 1 {
        return 1;
    }
    prev: int = 0;
    curr: int = 1;
    i: int = 2;
    while i <= n {
        next_val: int = prev + curr;
        prev = curr;
        curr = next_val;
        i += 1;
    }
    return curr;
}

