edge Dependency {
    has blocked: bool = False;
}

node Job {
    has effort: int = 0;
    has priority: int = 0;

    def rank() -> int {
        value: int = self.priority * 100;
        value -= self.effort;
        return value;
    }
}

def schedule_decision(a_effort: int, a_priority: int, b_effort: int, b_priority: int, blocked: bool) -> int {
    first: Job = Job(effort=a_effort, priority=a_priority);
    second: Job = Job(effort=b_effort, priority=b_priority);
    dep: Dependency = Dependency(blocked=blocked);
    if dep.blocked {
        return second.rank();
    }
    first_rank: int = first.rank();
    second_rank: int = second.rank();
    if first_rank > second_rank {
        return first_rank;
    } else {
        return second_rank;
    }
}

with entry {
    print(schedule_decision(30, 5, 10, 4, False));
    print(schedule_decision(30, 5, 10, 4, True));
}

